var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>양념장만 만들면 나머지는 식은 죽 먹기에요.</color>","JPN":"<color=#ffd34c>タレを作れば、あとは簡単です。</color>","ENG":"<color=#ffd34c>Once you make the sauce, the rest is easy.</color>","TWN":"<color=#ffd34c>只要做好沾醬，剩下的都是小菜一碟。</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>자, 재료를 보실까요?</color>","JPN":"<color=#ffd34c>さあ、こちらが材料になります。</color>","ENG":"<color=#ffd34c>Shall we take a look at the ingredients?</color>","TWN":"<color=#ffd34c>那麼，讓我們來看看材料吧？</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>먼저 고추장, 고춧가루, 마늘, 설탕, 간장, 맛술 한 컵씩 준비해서......</color>","JPN":"<color=#ffd34c>まず、コチュジャンと唐辛子粉、ニンニク、砂糖、醤油、みりんをスプーン1杯分用意して……</color>","ENG":"<color=#ffd34c>First, prepare a cup of pepper paste, chili powder, garlic, sugar, soy sauce and cooking wine each...</color>","TWN":"<color=#ffd34c>首先，準備紅辣椒醬、辣椒粉、大蒜、砂糖、醬油、味醂一小杯……</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"준비한 재료를 잘 섞어서...... 냉장고에 숙성시키면 맛이 깊어진다...... 음음......","JPN":"材料をしっかり混ぜて……冷蔵庫で寝かせると深い味わいになる……うんうん……","ENG":"Mix the ingredients well... And then age the sauce in the fridge to add depth to the flavor... Mm...","TWN":"把準備好的食材充分攪拌……然後放在冰箱裡發酵，味道就會變得更有深度……嗯嗯……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"와아, 인터넷에는 좋은 정보가 많네...... 역시 클로에 씨한테 물어보길 잘했어.","JPN":"わあ、インターネットには、いい情報がたくさんあるなぁ……やっぱりクロエさんに聞いておいてよかった。","ENG":"Wow, the internet sure has a lot of good info... I'm glad I asked Chloe.","TWN":"哇，網路上有好多好用的情報呢……果然有問題找克洛伊準沒錯。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"오늘 퇴근해서 양념장을 만들어 두면 내일 아침에 바로 쓸 수 있겠지?","JPN":"今日家に帰ってタレを作っておけば、明日の朝には使えるよね？","ENG":"If I make the sauce today after work, hopefully I'll be able to use it tomorrow morning.","TWN":"今天回家就把沾醬做好的話，明天早上就能直接使用了吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"헤헤, 다들 맛있게 먹을 수 있게......","JPN":"へへ、みんなでおいしく食べられるように……","ENG":"Heh, and then everyone can enjoy...","TWN":"嘿嘿，這樣大家就能吃得更香了……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"여기 있었구나, 멸치!","JPN":"ここにいたのか、イワシ！","ENG":"There you are, Weak Sauce!","TWN":"原來妳在這裡啊，小魚乾！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아, 유진아. 오늘 고생 많았어......","JPN":"あ、シロコ。お疲れ様……","ENG":"Oh, Eujin. Great work today...","TWN":"啊，劉珍，今天辛苦了……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"......아코!","JPN":"……いたっ！","ENG":"Ow!","TWN":"……唉哟！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"왜 불러? 바쁘니까 나중에 꿀꿀거려.","JPN":"何？今忙しいから、ブーブー鳴くのは後にして。","ENG":"What? I'm busy right now. Grunt at me later.","TWN":"叫我幹嘛？我很忙的，以後再說吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"리, 린. 서로 친구니까 조금은 부드럽게......","JPN":"リ、リン。友達なら、もう少し優しく……","ENG":"L-Lin. We're all friends here, could you tone down...","TWN":"琳、琳。大家都是朋友，稍微和氣一點……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"......아코!","JPN":"……いたっ！","ENG":"Ow!","TWN":"……唉哟！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아까 작전하다가 내 뒤통수에 대고 총알 갈긴 거 너지?!","JPN":"さっき作戦中に、俺の後頭部に弾をぶっ放したのはお前だな！？","ENG":"Were you the one who shot at me during the operation today?!","TWN":"剛才作戰的時候，對著我後腦開槍的就是妳吧？！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"내가 그랬나? 네가 통신에 대고 땅꼬마라고 놀리던 누군가가 열 받아서 그런 게 아닐까?","JPN":"さあ？あなたに通信でチビだとからかわれた誰かさんが、怒って撃ったのでは？","ENG":"Did I do that? Perhaps a certain someone who was ridiculed for her short stature over the comms got mad?","TWN":"我有嗎？不是因為妳在通信裡嘲笑某人是個小不點，把她惹火的關係？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이게 째째하게! 키 작은 게 불만이면 우유라도 먹으라고!","JPN":"ああ？チビって呼ばれたくなかったら牛乳でも飲め！","ENG":"You're so petty! If you want to grow, go drink more milk!","TWN":"這麼小心眼！妳不爽妳的身高，多喝點牛奶不就行了！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"너야말로 사선에서 얼쩡거리지 말라고 내가 몇 번을 말해!","JPN":"あなたこそ！私の射線をうろつくのはやめろって何回も言ったはず！","ENG":"And I told you over and over again to stop getting in my line of fire!","TWN":"妳才是，我都說過多少次了，不要衝到我的射擊範圍內亂晃！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"얘, 얘들아...... 싸우면 안 돼......","JPN":"ふ、二人とも……ケンカはよくないよ……","ENG":"G-guys... Please stop fighting...","TWN":"大、大家……不可以吵架……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저번에도 이러다가 부사장님이 휘말려서 머리에 혹까지 나셨잖아.","JPN":"この間も副社長が巻き込まれて、ものすごく怒られたじゃない。","ENG":"The Vice President got involved last time and she ended up getting a bump on her head.","TWN":"上次不是也是這樣，連副總都被捲進來，頭上還腫了個大包嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그, 그렇지! 오늘 저녁 메뉴는 어떤 게 좋아? 맛있게 만들어 줄 테니까......","JPN":"そ、そうだ！　今日の夕飯は何にする？　おいしく作って……","ENG":"Th-that's right! What do you want for dinner today? I'll cook up a really tasty one...","TWN":"對、對了！今天晚上你們想吃什麼？我幫你們做好吃的……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"시끄러워! 안경잡이는 빠져 있어!","JPN":"うるせえ！メガネは黙ってろ！","ENG":"Shut up! You stay out of this, Four-Eyes!","TWN":"吵死了！四眼仔閃一邊去！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아, 안경잡이......?! 그냥 눈이 나빠서 쓰고 다닐 뿐인데......?","JPN":"メ、メガネ……！？　私にはメガネじゃなくて、ちゃんとした名前が……","ENG":"F-Four-Eyes?! I'm just wearing glasses because my sight is hindered...","TWN":"四、四眼仔……？！我只是因為視力不好才戴眼鏡的呀……？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"맞아! 내숭쟁이!","JPN":"そうだよ！この猫かぶり！","ENG":"Yeah! You stay out, Prude!","TWN":"就是啊！愛裝乖的慣犯！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"내, 내숭쟁이......? 난 그저 말하는 게 서툴러서......","JPN":"ね、猫かぶり……？　私はただ、口下手なだけで……","ENG":"P-Prude? I'm just bad at talking to others...","TWN":"愛、愛裝乖的慣犯……？我只是不太會說話……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"얘들아, 잘 기다리고 있었어?","JPN":"みんな、待たせちゃってごめん。","ENG":"Hey, did I make you guys wait?","TWN":"夥伴們，你們等很久了嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"정산금 받아왔어. 당분간 예산 걱정은 없을 테니까 안심해.","JPN":"精算金をもらってきたわ。これで当分の間、お金の心配はいらないわね。","ENG":"I got our pay. We're not going to have any money problems for a while.","TWN":"我拿到了獎金。所以暫時不用擔心預算，可以安心了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"얘들아? 왜 그러고 있어?","JPN":"みんな？どうしたの？","ENG":"Guys? What's wrong?","TWN":"夥伴們？你們怎麼了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그래, 다 내가 잘못 키운 탓이야...... 다 내 탓이야......","JPN":"そうだよ、全部私のせいだよ……私が悪いんだ……","ENG":"This is my fault for not raising them properly... It's all my fault...","TWN":"對，都是我教得不好……全都要怪我……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"소빈아?","JPN":"コハル？","ENG":"Sobin?","TWN":"素蘋？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"어벙한 안경잡이에 착한 척하는 내숭쟁이니까 어쩔 수 없는걸...... 후후......","JPN":"間抜けなメガネをかけて、親切なふりをする猫かぶりなんだから仕方ないよ……ふふ……","ENG":"I'm just a stupid four-eyed prude who's pretending to be nice... *Chuckle*","TWN":"誰叫我不僅是個笨拙的四眼仔，還是假裝善良的愛裝乖慣犯……呵呵呵……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"등골 빠지게 청소에 밥에 빨래에 다 해 줬는데 클 만큼 컸다고 듣는 척도 안 하고......","JPN":"精一杯、掃除に料理、洗濯まで頑張ったのに、大きくなったからって全然言うこと聞かないし……","ENG":"I worked my butt off to clean, cook, and wash all your clothes. But now that you're all grown up, you won't even listen...","TWN":"我每天那麼盡心盡力地打掃、做飯、洗衣，翅膀硬了就開始無視我了……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"후...... 후후...... 후후후......","JPN":"ふ……ふふ……ふふふ……","ENG":"Hah... Hah hah... Hah hah hah...","TWN":"呵……呵呵……呵呵呵……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어...... 너네들 소빈이한테 무슨 짓을 한 거야?","JPN":"ちょっと……あなたたち、コハルに何をしたの？","ENG":"Uh... What did you guys do to Sobin?","TWN":"呃……你們對素蘋做了什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};